"""
Parameterized generator for GH1033_ray_23187.

Source PR:    https://github.com/ray-project/ray/pull/23187
Source Issue: https://github.com/ray-project/ray/issues/1234

Seed varies: renames 'calling' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH1033_ray_23187'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH1033_ray_23187'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('calling', 'calling' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH1033_ray_23187',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'ray-project/ray',
                "pr_number": 23187,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/ray-project/ray/pull/23187",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'python/ray/tests/test_actor_pool.py': 'import sys\nimport time\nimport pytest\n\nimport ray\nfrom ray.util import ActorPool\n\n\n@pytest.fixture\ndef init():\n    ray.init(num_cpus=4)\n    yield\n    ray.shutdown()\n\n\ndef test_get_next(init):\n    @ray.remote\n    class MyActor:\n        def __init__(self):\n            pass\n\n        def f(self, x):\n            return x + 1\n\n        def double(self, x):\n            return 2 * x\n\n    actors = [MyActor.remote() for _ in range(4)]\n    pool = ActorPool(actors)\n    for i in range(5):\n        pool.submit(lambda a, v: a.f.remote(v), i)\n        assert pool.get_next() == i + 1\n\n\ndef test_get_next_unordered(init):\n    @ray.remote\n    class MyActor:\n        def __init__(self):\n            pass\n\n        def f(self, x):\n            return x + 1\n\n        def double(self, x):\n            return 2 * x\n\n    actors = [MyActor.remote() for _ in range(4)]\n    pool = ActorPool(actors)\n\n    total = []\n\n    for i in range(5):\n        pool.submit(lambda a, v: a.f.remote(v), i)\n    while pool.has_next():\n        total += [pool.get_next_unordered()]\n\n    assert all(elem in [1, 2, 3, 4, 5] for elem in total)\n\n\ndef test_map(init):\n    @ray.remote\n    class MyActor:\n        def __init__(self):\n            pass\n\n        def f(self, x):\n            return x + 1\n\n        def double(self, x):\n            return 2 * x\n\n    actors = [MyActor.remote() for _ in range(4)]\n    pool = ActorPool(actors)\n\n    index = 0\n    for v in pool.map(lambda a, v: a.double.remote(v), range(5)):\n        assert v == 2 * index\n        index += 1\n\n\ndef test_map_unordered(init):\n    @ray.remote\n    class MyActor:\n        def __init__(self):\n            pass\n\n        def f(self, x):\n            return x + 1\n\n        def double(self, x):\n            return 2 * x\n\n    actors = [MyActor.remote() for _ in range(4)]\n    pool = ActorPool(actors)\n\n    total = []\n    for v in pool.map(lambda a, v: a.double.remote(v), range(5)):\n        total += [v]\n\n    assert all(elem in [0, 2, 4, 6, 8] for elem in total)\n\n\ndef test_get_next_timeout(init):\n    @ray.remote\n    class MyActor:\n        def __init__(self):\n            pass\n\n        def f(self, x):\n            while True:\n                x = x + 1\n                time.sleep(1)\n            return None\n\n        def double(self, x):\n            return 2 * x\n\n    actors = [MyActor.remote() for _ in range(4)]\n    pool = ActorPool(actors)\n    pool.submit(lambda a, v: a.f.remote(v), 0)\n    with pytest.raises(TimeoutError):\n        pool.get_next_unordered(timeout=0.1)\n\n\ndef test_get_next_unordered_timeout(init):\n    @ray.remote\n    class MyActor:\n        def __init__(self):\n            pass\n\n        def f(self, x):\n            while True:\n                x + 1\n                time.sleep(1)\n            return\n\n        def double(self, x):\n            return 2 * x\n\n    actors = [MyActor.remote() for _ in range(4)]\n    pool = ActorPool(actors)\n\n    pool.submit(lambda a, v: a.f.remote(v), 0)\n    with pytest.raises(TimeoutError):\n        pool.get_next_unordered(timeout=0.1)\n\n\ndef test_multiple_returns(init):\n    @ray.remote\n    class Foo(object):\n        @ray.method(num_returns=2)\n        def bar(self):\n            return 1, 2\n\n    pool = ActorPool([Foo.remote() for _ in range(2)])\n    for _ in range(4):\n        pool.submit(lambda a, v: a.bar.remote(), None)\n\n    while pool.has_next():\n        assert pool.get_next(timeout=None) == [1, 2]\n\n\ndef test_pop_idle(init):\n    @ray.remote\n    class MyActor:\n        def __init__(self):\n            pass\n\n        def f(self, x):\n            return x + 1\n\n        def double(self, x):\n            return 2 * x\n\n    actors = [MyActor.remote()]\n    pool = ActorPool(actors)\n\n    pool.submit(lambda a, v: a.double.remote(v), 1)\n    assert pool.pop_idle() is None\n    assert pool.has_free() is False  # actor is busy\n    assert pool.get_next() == 2\n    assert pool.has_free()\n    pool.pop_idle()  # removes actor from pool\n    assert pool.has_free() is False  # no more actors in pool\n\n\ndef test_push(init):\n    @ray.remote\n    class MyActor:\n        def __init__(self):\n            pass\n\n        def f(self, x):\n            return x + 1\n\n        def double(self, x):\n            return 2 * x\n\n    a1, a2 = MyActor.remote(), MyActor.remote()\n    pool = ActorPool([a1])\n\n    pool.submit(lambda a, v: a.double.remote(v), 1)\n    assert pool.has_free() is False  # actor is busy\n    with pytest.raises(ValueError):\n        pool.push(a1)\n    pool.push(a2)\n    assert pool.has_free()  # a2 is available\n\n\nif __name__ == "__main__":\n    sys.exit(pytest.main(["-v", __file__]))\n',
            'python/ray/util/actor_pool.py': 'import ray\nfrom ray.util.annotations import PublicAPI\n\n\n@PublicAPI(stability="beta")\nclass ActorPool:\n    """Utility class to operate on a fixed pool of actors.\n\n    Arguments:\n        actors (list): List of Ray actor handles to use in this pool.\n\n    Examples:\n        >>> a1, a2 = Actor.remote(), Actor.remote()\n        >>> pool = ActorPool([a1, a2])\n        >>> print(list(pool.map(lambda a, v: a.double.remote(v),\\\n        ...                     [1, 2, 3, 4])))\n        [2, 4, 6, 8]\n    """\n\n    def __init__(self, actors):\n        # actors to be used\n        self._idle_actors = list(actors)\n\n        # get actor from future\n        self._future_to_actor = {}\n\n        # get future from index\n        self._index_to_future = {}\n\n        # next task to do\n        self._next_task_index = 0\n\n        # next task to return\n        self._next_return_index = 0\n\n        # next work depending when actors free\n        self._pending_submits = []\n\n    def map(self, fn, values):\n        """Apply the given function in parallel over the actors and values.\n\n        This returns an ordered iterator that will return results of the map\n        as they finish. Note that you must iterate over the iterator to force\n        the computation to finish.\n\n        Arguments:\n            fn (func): Function that takes (actor, value) as argument and\n                returns an ObjectRef computing the result over the value. The\n                actor will be considered busy until the ObjectRef completes.\n            values (list): List of values that fn(actor, value) should be\n                applied to.\n\n        Returns:\n            Iterator over results from applying fn to the actors and values.\n\n        Examples:\n            >>> pool = ActorPool(...)\n            >>> print(list(pool.map(lambda a, v: a.double.remote(v),\\\n            ...                     [1, 2, 3, 4])))\n            [2, 4, 6, 8]\n        """\n        for v in values:\n            self.submit(fn, v)\n        while self.has_next():\n            yield self.get_next()\n\n    def map_unordered(self, fn, values):\n        """Similar to map(), but returning an unordered iterator.\n\n        This returns an unordered iterator that will return results of the map\n        as they finish. This can be more efficient that map() if some results\n        take longer to compute than others.\n\n        Arguments:\n            fn (func): Function that takes (actor, value) as argument and\n                returns an ObjectRef computing the result over the value. The\n                actor will be considered busy until the ObjectRef completes.\n            values (list): List of values that fn(actor, value) should be\n                applied to.\n\n        Returns:\n            Iterator over results from applying fn to the actors and values.\n\n        Examples:\n            >>> pool = ActorPool(...)\n            >>> print(list(pool.map_unordered(lambda a, v: a.double.remote(v),\\\n            ...                               [1, 2, 3, 4])))\n            [6, 2, 4, 8]\n        """\n        for v in values:\n            self.submit(fn, v)\n        while self.has_next():\n            yield self.get_next_unordered()\n\n    def submit(self, fn, value):\n        """Schedule a single task to run in the pool.\n\n        This has the same argument semantics as map(), but takes on a single\n        value instead of a list of values. The result can be retrieved using\n        get_next() / get_next_unordered().\n\n        Arguments:\n            fn (func): Function that takes (actor, value) as argument and\n                returns an ObjectRef computing the result over the value. The\n                actor will be considered busy until the ObjectRef completes.\n            value (object): Value to compute a result for.\n\n        Examples:\n            >>> pool = ActorPool(...)\n            >>> pool.submit(lambda a, v: a.double.remote(v), 1)\n            >>> pool.submit(lambda a, v: a.double.remote(v), 2)\n            >>> print(pool.get_next(), pool.get_next())\n            2, 4\n        """\n        if self._idle_actors:\n            actor = self._idle_actors.pop()\n            future = fn(actor, value)\n            future_key = tuple(future) if isinstance(future, list) else future\n            self._future_to_actor[future_key] = (self._next_task_index, actor)\n            self._index_to_future[self._next_task_index] = future\n            self._next_task_index += 1\n        else:\n            self._pending_submits.append((fn, value))\n\n    def has_next(self):\n        """Returns whether there are any pending results to return.\n\n        Returns:\n            True if there are any pending results not yet returned.\n\n        Examples:\n            >>> pool = ActorPool(...)\n            >>> pool.submit(lambda a, v: a.double.remote(v), 1)\n            >>> print(pool.has_next())\n            True\n            >>> print(pool.get_next())\n            2\n            >>> print(pool.has_next())\n            False\n        """\n        return bool(self._future_to_actor)\n\n    def get_next(self, timeout=None):\n        """Returns the next pending result in order.\n\n        This returns the next result produced by submit(), blocking for up to\n        the specified timeout until it is available.\n\n        Returns:\n            The next result.\n\n        Raises:\n            TimeoutError if the timeout is reached.\n\n        Examples:\n            >>> pool = ActorPool(...)\n            >>> pool.submit(lambda a, v: a.double.remote(v), 1)\n            >>> print(pool.get_next())\n            2\n        """\n        if not self.has_next():\n            raise StopIteration("No more results to get")\n        if self._next_return_index >= self._next_task_index:\n            raise ValueError(\n                "It is not allowed to call get_next() after " "get_next_unordered()."\n            )\n        future = self._index_to_future[self._next_return_index]\n        if timeout is not None:\n            res, _ = ray.wait([future], timeout=timeout)\n            if not res:\n                raise TimeoutError("Timed out waiting for result")\n        del self._index_to_future[self._next_return_index]\n        self._next_return_index += 1\n\n        future_key = tuple(future) if isinstance(future, list) else future\n        i, a = self._future_to_actor.pop(future_key)\n\n        self._return_actor(a)\n        return ray.get(future)\n\n    def get_next_unordered(self, timeout=None):\n        """Returns any of the next pending results.\n\n        This returns some result produced by submit(), blocking for up to\n        the specified timeout until it is available. Unlike get_next(), the\n        results are not always returned in same order as submitted, which can\n        improve performance.\n\n        Returns:\n            The next result.\n\n        Raises:\n            TimeoutError if the timeout is reached.\n\n        Examples:\n            >>> pool = ActorPool(...)\n            >>> pool.submit(lambda a, v: a.double.remote(v), 1)\n            >>> pool.submit(lambda a, v: a.double.remote(v), 2)\n            >>> print(pool.get_next_unordered())\n            4\n            >>> print(pool.get_next_unordered())\n            2\n        """\n        if not self.has_next():\n            raise StopIteration("No more results to get")\n        # TODO(ekl) bulk wait for performance\n        res, _ = ray.wait(list(self._future_to_actor), num_returns=1, timeout=timeout)\n        if res:\n            [future] = res\n        else:\n            raise TimeoutError("Timed out waiting for result")\n        i, a = self._future_to_actor.pop(future)\n        self._return_actor(a)\n        del self._index_to_future[i]\n        self._next_return_index = max(self._next_return_index, i + 1)\n        return ray.get(future)\n\n    def _return_actor(self, actor):\n        self._idle_actors.append(actor)\n        if self._pending_submits:\n            self.submit(*self._pending_submits.pop(0))\n\n    def has_free(self):\n        """Returns whether there are any idle actors available.\n\n        Returns:\n            True if there are any idle actors and no pending submits.\n\n        Examples:\n            >>> a1 = Actor.remote()\n            >>> pool = ActorPool(a1)\n            >>> pool.submit(lambda a, v: a.double.remote(v), 1)\n            >>> print(pool.has_free())\n            False\n            >>> print(pool.get_next())\n            2\n            >>> print(pool.has_free())\n            True\n        """\n        return len(self._idle_actors) > 0 and len(self._pending_submits) == 0\n\n    def pop_idle(self):\n        """Removes an idle actor from the pool.\n\n        Returns:\n            An idle actor if one is available.\n            None if no actor was free to be removed.\n\n        Examples:\n            >>> a1 = Actor.remote()\n            >>> pool = ActorPool([a1])\n            >>> pool.submit(lambda a, v: a.double.remote(v), 1)\n            >>> print(pool.pop_idle())\n            None\n            >>> print(pool.get_next())\n            2\n            >>> print(pool.pop_idle())\n            <ptr to a1>\n        """\n        if self.has_free():\n            return self._idle_actors.pop()\n        return None\n\n    def push(self, actor):\n        """Pushes a new actor into the current list of idle actors.\n\n        Examples:\n            >>> a1, b1 = Actor.remote(), Actor.remote()\n            >>> pool = ActorPool([a1])\n            >>> pool.submit(lambda a, v: a.double.remote(v), 1)\n            >>> print(pool.get_next())\n            2\n            >>> pool2 = ActorPool([b1])\n            >>> pool2.push(pool.pop_idle())\n        """\n        busy_actors = []\n        if self._future_to_actor.values():\n            _, busy_actors = zip(*self._future_to_actor.values())\n        if actor in self._idle_actors or actor in busy_actors:\n            raise ValueError("Actor already belongs to current ActorPool")\n        else:\n            self._idle_actors.append(actor)\n',
        }
